// ---- Clean date ----
const rawDate = msg.payload.order_date || "";

const cleanedDate = rawDate
  .replace(/^[A-Za-z]+,\s*/, '')
  .replace(/\sIST$/, '');

const parsedDate = new Date(cleanedDate + ' GMT+0530');
const eventTime = isNaN(parsedDate.getTime()) ? null : parsedDate.getTime();

