  order_id: msg.payload.order_no || null,
  order_date: rawDate,
  buyer_name: msg.payload.buyer || null,
  city: cleanCity,
  state: cleanState,
  sku: msg.payload.sku || null,
  description: msg.payload.description || null,
  quantity: msg.payload.quantity ? Number(msg.payload.quantity) : null,
  amount: cleanAmount,
  event_time: eventTime
};


