try {

  if (format === "csv") {
    // CSV format: order_id,amount,city
    msg.payload = `${order.order_id},${order.amount},${order.city}`;
  }

  else if (format === "xml") {
    // XML format
    msg.payload = `<order>
  <order_id>${order.order_id}</order_id>
  <amount>${order.amount}</amount>
  <city>${order.city}</city>
</order>`;
  }

  else {
    // JSON format (default)
    msg.payload = JSON.stringify({
      order_id: order.order_id,
      amount: order.amount,
      city: order.city
    });
  }

} catch (err) {
  node.error("Format conversion error: " + err);
  return null;
}

return msg;

const city = (msg.req.query.city || "BENGALURU").toUpperCase();
const name = (msg.req.query.name || "").toUpperCase();
