let query = `
SELECT
   order_id,
   order_date,
   buyer_name,
   city,
   state,
   sku,
   description,
   quantity,
   amount,
   event_time
FROM ORDERS_BY_CITY_NAME
WHERE city='${city}'
`;

if (name) {
    query += ` AND buyer_name='${name}'`;
}

query += ` LIMIT ${limit};`;

msg.payload = { ksql: query };

return msg;

// ksqlDB response example:
// [
