    if (!r || !r.row || !Array.isArray(r.row.columns)) continue;

    const c = r.row.columns;

    // DEBUG (optional - remove later)
    // node.warn(c);

    /*
      IMPORTANT:
      Because you are using MATERIALIZED TABLE,
      first column = TABLE KEY (city)

      So actual order becomes:

      c[0] = key_city
      c[1] = order_id
      c[2] = order_date
      c[3] = buyer_name
      c[4] = city
      c[5] = state
      c[6] = sku
      c[7] = description
      c[8] = quantity
      c[9] = amount
      c[10] = event_time
    */

    result.push({
    order_id: c[0],
    buyer_name: c[1],
    city: c[2],
    state: c[3],
    order_date: c[4],
    sku: c[5],
    description: c[6],
    quantity: Number(c[7]),
    amount: Number(c[8]),
    event_time: c[9] ? Number(c[9]) : null
});
}

// send clean array to React
msg.payload = result;

return msg;

